const url = $input.first().json.body?.url || $input.first().json.url;
const title = $input.first().json.body?.title || $input.first().json.title || '';

if (!url) throw new Error('يرجى إرسال رابط في حقل url');

// تحديد نوع الرابط
let type = 'webpage';
if (url.includes('youtube.com') || url.includes('youtu.be')) type = 'youtube';
else if (url.includes('twitter.com') || url.includes('x.com')) type = 'twitter';
else if (url.includes('linkedin.com')) type = 'linkedin';
else if (url.includes('facebook.com') || url.includes('fb.com')) type = 'facebook';
else if (url.includes('instagram.com')) type = 'instagram';
else if (url.includes('tiktok.com')) type = 'tiktok';
else if (url.match(/\.(mp3|wav|ogg|m4a|aac)$/i)) type = 'audio';
else if (url.match(/\.(mp4|avi|mov|mkv|webm)$/i)) type = 'video';
else if (url.match(/\.(pdf)$/i)) type = 'pdf';

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
const safeTitle = title.replace(/[^\u0600-\u06FFa-zA-Z0-9\s]/g, '').trim().slice(0, 50) || type;
const filename = `${timestamp}_${safeTitle}.md`;

return [{ json: { url, type, title, filename, timestamp } }];

// جمع النتائج من أي مسار
const input = $input.first().json;
const prevData = $('🔍 تحديد نوع الرابط').first().json;

let content = '';
let source = '';

// من YouTube transcript
if (input.transcript) {
  content = input.transcript;
  source = 'YouTube Transcript';
}
// من Jina Reader (body كنص)
else if (typeof input.body === 'string' && input.body.length > 100) {
  content = input.body;
  source = 'Jina.ai Reader';
}
// من Jina Reader (data)
else if (input.data) {
  content = typeof input.data === 'string' ? input.data : JSON.stringify(input.data);
  source = 'Jina.ai Reader';
}
else {
  content = JSON.stringify(input);
  source = 'Raw Response';
}

// تنظيف المحتوى
content = content
  .replace(/\[\d+\]/g, '')  // إزالة مراجع الأرقام
  .replace(/\n{3,}/g, '\n\n')  // تقليل الأسطر الفارغة المتكررة
  .trim();

const wordCount = content.split(/\s+/).length;

return [{ json: {
  ...prevData,
  content,
  source,
  wordCount,
  contentPreview: content.slice(0, 200)
}}];

const data = $input.first().json;
const aiResponse = data.response || '';

// بناء ملف Markdown منظم
const markdown = `---
title: "${data.title || data.url}"
url: ${data.url}
type: ${data.type}
source: ${data.source}
date: ${data.timestamp}
words: ${data.wordCount}
---

# ${data.title || 'محتوى من: ' + data.url}

**المصدر:** ${data.url}  
**النوع:** ${data.type}  
**التاريخ:** ${new Date(data.timestamp).toLocaleDateString('ar-SA')}  
**عدد الكلمات:** ${data.wordCount}

---

## 📋 الملخص الذكي

${aiResponse}

---

## 📄 المحتوى الكامل

${data.content}
`;

return [{ json: {
  ...data,
  markdown,
  filename: data.filename
}}];
